// ── HELPERS ───────────────────────────────────────────────────
const fmtR  = n => n != null ? `R ${Number(n).toLocaleString("en-ZA")}` : "—";
const fmtK  = n => n >= 1000 ? `R ${(n / 1000).toFixed(0)}k` : fmtR(n);
const pct   = (a, b) => b > 0 ? Math.round((a / b) * 100) : 0;
function daysUntil(d) { return d ? Math.ceil((new Date(d) - Date.now()) / 86400000) : null; }
function timeAgo(s) {
  if (!s) return "";
  const d = (Date.now() - new Date(s)) / 1000;
  if (d < 60)    return "Just now";
  if (d < 3600)  return `${Math.floor(d / 60)}m ago`;
  if (d < 86400) return `${Math.floor(d / 3600)}h ago`;
  return `${Math.floor(d / 86400)}d ago`;
}
function formatDate(d) {
  return d ? new Date(d).toLocaleDateString("en-ZA", { day: "2-digit", month: "short" }) : "—";
}

// ── SVG RING METER ────────────────────────────────────────────
// Animated donut ring showing a percentage with a label
function RingMeter({ value, max = 100, color, label, sublabel, size = 96, stroke = 7 }) {
  const [animated, setAnimated] = useState(0);
  const r   = (size - stroke * 2) / 2;
  const circ = 2 * Math.PI * r;
  const ratio = Math.min(value / max, 1);

  useEffect(() => {
    const t = setTimeout(() => setAnimated(ratio), 80);
    return () => clearTimeout(t);
  }, [ratio]);

  const displayVal = max === 100 ? `${value}%` : fmtK(value);

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: ".5rem" }}>
      <div style={{ position: "relative", width: size, height: size }}>
        <svg width={size} height={size} style={{ transform: "rotate(-90deg)" }}>
          {/* Track */}
          <circle cx={size / 2} cy={size / 2} r={r}
            fill="none" stroke="rgba(245,240,232,0.06)" strokeWidth={stroke} />
          {/* Fill */}
          <circle cx={size / 2} cy={size / 2} r={r}
            fill="none" stroke={color} strokeWidth={stroke}
            strokeDasharray={circ}
            strokeDashoffset={circ - animated * circ}
            strokeLinecap="round"
            style={{ transition: "stroke-dashoffset 1s cubic-bezier(.4,0,.2,1)" }} />
        </svg>
        {/* Centre label */}
        <div style={{
          position: "absolute", inset: 0, display: "flex",
          flexDirection: "column", alignItems: "center", justifyContent: "center",
        }}>
          <span style={{ fontSize: size < 88 ? ".75rem" : ".9rem", fontFamily: F.bebas, color, letterSpacing: ".04em", lineHeight: 1 }}>
            {displayVal}
          </span>
        </div>
      </div>
      <div style={{ textAlign: "center" }}>
        <p style={{ fontSize: ".65rem", fontWeight: 600, color: C.white, fontFamily: F.dm, marginBottom: "1px" }}>{label}</p>
        {sublabel && <p style={{ fontSize: ".55rem", fontFamily: F.mono, color: "rgba(245,240,232,.3)", letterSpacing: ".05em" }}>{sublabel}</p>}
      </div>
    </div>
  );
}

// ── HEAT MATRIX ───────────────────────────────────────────────
// A grid of unit × month cells colour-coded by payment status
const MONTHS = ["Nov", "Dec", "Jan", "Feb", "Mar", "Apr"];
const STATUS_COLOR = {
  paid:       "#1A7A4A",
  late:       "#E8A012",
  missed:     "#E05A4A",
  pending:    "#3A8FD4",
  vacant:     "rgba(245,240,232,0.04)",
};
const STATUS_LABEL = { paid: "Paid", late: "Late", missed: "Missed", pending: "Pending", vacant: "Vacant" };

function HeatMatrix({ properties }) {
  const [tooltip, setTooltip] = useState(null);

  return (
    <div>
      {/* Legend */}
      <div style={{ display: "flex", gap: ".8rem", flexWrap: "wrap", marginBottom: "1rem" }}>
        {Object.entries(STATUS_LABEL).map(([k, v]) => (
          <div key={k} style={{ display: "flex", alignItems: "center", gap: ".3rem" }}>
            <span style={{ width: 8, height: 8, borderRadius: "1px", background: STATUS_COLOR[k], flexShrink: 0, border: k === "vacant" ? "1px solid rgba(245,240,232,.1)" : "none" }} />
            <span style={{ fontSize: ".52rem", fontFamily: F.mono, color: "rgba(245,240,232,.3)", letterSpacing: ".06em", textTransform: "uppercase" }}>{v}</span>
          </div>
        ))}
      </div>

      {/* Month headers */}
      <div style={{ display: "grid", gridTemplateColumns: "6rem repeat(6, 1fr)", gap: "3px", marginBottom: "3px" }}>
        <span />
        {MONTHS.map(m => (
          <span key={m} style={{ fontSize: ".48rem", fontFamily: F.mono, color: "rgba(245,240,232,.25)", letterSpacing: ".08em", textAlign: "center", textTransform: "uppercase" }}>{m}</span>
        ))}
      </div>

      {/* Rows per property */}
      {properties.map((prop, pi) => (
        <div key={prop.name}>
          {/* Property name row */}
          <div style={{ padding: ".35rem 0 .2rem", marginTop: pi > 0 ? ".6rem" : 0 }}>
            <span style={{ fontSize: ".58rem", fontFamily: F.mono, letterSpacing: ".08em", color: "rgba(245,240,232,.4)", textTransform: "uppercase" }}>{prop.name}</span>
          </div>
          {/* Unit rows */}
          {prop.units.map((unit, ui) => (
            <div key={unit.id} style={{ display: "grid", gridTemplateColumns: "6rem repeat(6, 1fr)", gap: "3px", marginBottom: "3px" }}>
              <div style={{ display: "flex", alignItems: "center" }}>
                <span style={{ fontSize: ".58rem", fontFamily: F.mono, color: "rgba(245,240,232,.35)" }}>Unit {unit.number}</span>
              </div>
              {unit.months.map((status, mi) => (
                <div key={mi}
                  onMouseEnter={e => setTooltip({ status, unit: unit.number, month: MONTHS[mi], prop: prop.name, x: e.clientX, y: e.clientY })}
                  onMouseLeave={() => setTooltip(null)}
                  style={{
                    height: 22, borderRadius: "2px",
                    background: STATUS_COLOR[status],
                    border: status === "vacant" ? "1px solid rgba(245,240,232,.07)" : "none",
                    cursor: "pointer", transition: "opacity .15s",
                  }}
                  onMouseOver={e => e.currentTarget.style.opacity = ".75"}
                  onMouseOut={e => e.currentTarget.style.opacity = "1"}
                />
              ))}
            </div>
          ))}
        </div>
      ))}

      {/* Floating tooltip */}
      {tooltip && (
        <div style={{
          position: "fixed", top: tooltip.y - 48, left: tooltip.x + 10,
          background: C.muted2, border: `1px solid ${C.border}`,
          borderRadius: "3px", padding: ".35rem .6rem",
          fontSize: ".62rem", fontFamily: F.mono, color: C.white,
          pointerEvents: "none", zIndex: 100, whiteSpace: "nowrap",
        }}>
          {tooltip.prop} · Unit {tooltip.unit} · {tooltip.month}
          <span style={{ marginLeft: ".5rem", color: STATUS_COLOR[tooltip.status] }}>
            {STATUS_LABEL[tooltip.status]}
          </span>
        </div>
      )}
    </div>
  );
}

// ── EVENT TIMELINE ────────────────────────────────────────────
const EVT_ICONS = {
  payment_submitted:   { icon: "credit-card",     color: "#3A8FD4" },
  payment_approved:    { icon: "check",            color: "#1A7A4A" },
  payment_rejected:    { icon: "x",               color: "#E05A4A" },
  lease_expiring:      { icon: "clock",            color: "#E8A012" },
  maintenance_requested:{ icon: "tool",            color: "#8B5CF6" },
  maintenance_completed:{ icon: "check",           color: "#1A7A4A" },
  complaint_filed:     { icon: "message-square",   color: "#f59e0b" },
  overdue:             { icon: "alert-circle",     color: "#E05A4A" },
};

function TimelineEvent({ event, last }) {
  const cfg = EVT_ICONS[event.type] || EVT_ICONS.payment_submitted;
  return (
    <div style={{ display: "flex", gap: ".7rem", position: "relative" }}>
      {/* Spine */}
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", flexShrink: 0 }}>
        <div style={{
          width: 28, height: 28, borderRadius: "50%",
          background: `${cfg.color}14`,
          border: `1px solid ${cfg.color}30`,
          display: "flex", alignItems: "center", justifyContent: "center",
          flexShrink: 0, zIndex: 1,
        }}>
          <Icon name={cfg.icon} size={12} color={cfg.color} />
        </div>
        {!last && <div style={{ width: 1, flex: 1, background: "rgba(42,42,42,.8)", marginTop: "3px", minHeight: 20 }} />}
      </div>
      {/* Content */}
      <div style={{ paddingBottom: last ? 0 : "1rem", flex: 1, minWidth: 0 }}>
        <p style={{ fontSize: ".72rem", color: "rgba(245,240,232,.75)", fontFamily: F.dm, lineHeight: 1.4, marginBottom: "2px" }}>
          {event.message}
        </p>
        <div style={{ display: "flex", alignItems: "center", gap: ".5rem", flexWrap: "wrap" }}>
          <span style={{ fontSize: ".56rem", fontFamily: F.mono, color: "rgba(245,240,232,.2)" }}>{timeAgo(event.created_at)}</span>
          {event.amount && (
            <span style={{ fontSize: ".56rem", fontFamily: F.mono, color: cfg.color, fontWeight: 600 }}>{fmtR(event.amount)}</span>
          )}
          {event.tag && (
            <span style={{
              fontSize: ".5rem", fontFamily: F.mono, letterSpacing: ".06em", textTransform: "uppercase",
              color: cfg.color, background: `${cfg.color}12`,
              border: `1px solid ${cfg.color}20`, borderRadius: "2px", padding: "1px 5px",
            }}>{event.tag}</span>
          )}
        </div>
      </div>
    </div>
  );
}

