// ── PANEL WRAPPER ─────────────────────────────────────────────
function Panel({ title, children, action, onAction, style = {} }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", ...style }}>
      <div style={{
        display: "flex", alignItems: "center", justifyContent: "space-between",
        padding: ".8rem 1.2rem",
        borderBottom: `1px solid ${C.border}`,
        background: C.muted,
        flexShrink: 0,
      }}>
        <span style={{ fontSize: ".55rem", fontFamily: F.mono, letterSpacing: ".14em", color: "rgba(245,240,232,.3)", fontWeight: 700, textTransform: "uppercase" }}>
          {title}
        </span>
        {action && (
          <button onClick={onAction} style={{
            background: "none", border: "none", cursor: "pointer",
            fontSize: ".52rem", fontFamily: F.mono, color: C.gold, letterSpacing: ".06em",
          }}>
            {action} →
          </button>
        )}
      </div>
      <div style={{ flex: 1, overflow: "auto", padding: "1rem 1.2rem" }}>
        {children}
      </div>
    </div>
  );
}

// ── ALERT BADGE ───────────────────────────────────────────────
function AlertBadge({ count, color, label, icon, onClick }) {
  if (!count || count === 0) return null;
  return (
    <button onClick={onClick} style={{
      display: "flex", alignItems: "center", gap: ".5rem",
      padding: ".55rem .8rem",
      background: `${color}08`,
      border: `1px solid ${color}20`,
      borderRadius: "3px", cursor: "pointer",
      transition: "all .15s", width: "100%",
      marginBottom: ".4rem",
    }}
      onMouseEnter={e => e.currentTarget.style.background = `${color}14`}
      onMouseLeave={e => e.currentTarget.style.background = `${color}08`}
    >
      <div style={{ width: 24, height: 24, borderRadius: "50%", background: `${color}18`, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
        <Icon name={icon} size={12} color={color} />
      </div>
      <span style={{ flex: 1, fontSize: ".68rem", color: "rgba(245,240,232,.65)", fontFamily: F.dm, textAlign: "left" }}>{label}</span>
      <span style={{ fontFamily: F.bebas, fontSize: "1rem", color, letterSpacing: ".04em", lineHeight: 1 }}>{count}</span>
    </button>
  );
}

