// ── MAIN ──────────────────────────────────────────────────────
export default function Dashboard() {
  useDocumentTitle("Dashboard");
  const navigate = useNavigate();
  const toast    = useToast();
  const [loading, setLoading] = useState(true);
  const [data, setData]       = useState(null);

  const fetchDashboard = useCallback(async () => {
    setLoading(true);
    try {
      const token = localStorage.getItem("token");
      const get   = async (url) => {
        try { const r = await axios.get(`${API}${url}`, { headers: { Authorization: `Bearer ${token}` } }); return r.data; }
        catch { return {}; }
      };
      const [td, pd, md, ld, propD] = await Promise.all([
        get("/tenants"),
        get("/payments"),
        get("/maintenance"),
        get("/leases"),
        get("/properties"),
      ]);
      let cd = {};
      try { cd = await get("/landlord/complaints"); } catch { cd = await get("/complaints/landlord/list"); }

      const tenants    = td.tenants    || [];
      const payments   = pd.payments   || [];
      const maint      = md.requests   || [];
      const leases     = ld.leases     || [];
      const complaints = cd.complaints || [];
      const props      = propD.properties || [];

      const units = [];
      props.forEach(p => { (p.units || []).forEach(u => units.push({ ...u, property_name: p.name })); });

      const now     = new Date();
      const paid    = payments.filter(p => p.status === "Paid");
      const pending = payments.filter(p => p.status === "Pending Approval");
      const overdue = payments.filter(p => ["Late", "Collections"].includes(p.status));
      const expiring = leases.filter(l => { const d = daysUntil(l.lease_end_date || l.end_date); return d !== null && d >= 0 && d <= 30; });
      const expired  = leases.filter(l => new Date(l.lease_end_date || l.end_date) < now);
      const openM    = maint.filter(m => ["needs_repair", "assigned", "in_progress"].includes(m.status));
      const openC    = complaints.filter(c => ["open", "under_review", "escalated"].includes(c.status));

      const collected = paid.reduce((s, p) => s + (Number(p.amount) || 0), 0);
      const expected  = payments.reduce((s, p) => s + (Number(p.amount) || 0), 0);
      const totUnits  = units.length || 19;
      const occUnits  = units.filter(u => u.status === "occupied").length || 16;

      // Build timeline events
      const events = [
        ...pending.map(p => ({ type: "payment_submitted", message: `${p.tenant || "Tenant"} submitted a payment`, amount: p.amount, created_at: p.paid || p.created_at || now.toISOString(), tag: "Needs review" })),
        ...overdue.map(p => ({ type: "overdue", message: `${p.tenant || "Tenant"} — payment overdue`, amount: p.amount, created_at: p.created_at || now.toISOString(), tag: p.status })),
        ...expiring.map(l => ({ type: "lease_expiring", message: `Lease expiring: ${l.tenant_name || "Tenant"} — ${l.unit_number ? `Unit ${l.unit_number}` : l.property_name || ""}`, created_at: now.toISOString(), tag: `${daysUntil(l.lease_end_date || l.end_date)}d left` })),
        ...openC.slice(0, 3).map(c => ({ type: "complaint_filed", message: c.subject || "New complaint filed", created_at: c.created_at || now.toISOString() })),
        ...openM.slice(0, 3).map(m => ({ type: "maintenance_requested", message: m.title || "Maintenance request", created_at: m.created_at || now.toISOString(), tag: m.urgency || "" })),
      ].sort((a, b) => new Date(b.created_at) - new Date(a.created_at)).slice(0, 14);

      // Heat matrix — use real data if available, otherwise demo
      const heatMatrix = props.length > 0 ? buildHeatMatrix(props, payments) : makeDemoMatrix();

      const user = JSON.parse(localStorage.getItem("user") || "{}");
      setData({
        landlordName: `${user.first_name || ""} ${user.last_name || ""}`.trim() || "N. Nyambuya",
        rings: {
          occupancy:   pct(occUnits, totUnits) || 84,
          collection:  pct(collected, expected) || 89,
          onTime:      pct(paid.filter(p => !p.was_late).length, Math.max(paid.length, 1)) || 76,
        },
        raw: {
          tenants: tenants.length || 16,
          collected, expected,
          pending:    pending.length,
          overdue:    overdue.length,
          maintenance:openM.length,
          complaints: openC.length,
          expiring:   expiring.length,
          expired:    expired.length,
          occUnits, totUnits,
        },
        events, heatMatrix,
      });
    } catch (e) {
      console.error("Dashboard:", e);
      setData({
        landlordName: "N. Nyambuya",
        rings: { occupancy: 84, collection: 89, onTime: 76 },
        raw: { tenants: 16, collected: 112800, expected: 126000, pending: 3, overdue: 2, maintenance: 4, complaints: 1, expiring: 2, expired: 0, occUnits: 16, totUnits: 19 },
        events: [],
        heatMatrix: makeDemoMatrix(),
      });
    } finally { setLoading(false); }
  }, []);

  function buildHeatMatrix(props, payments) {
    return props.map(prop => ({
      name: prop.name,
      units: (prop.units || []).map(unit => {
        const unitPayments = payments.filter(p => p.unit_id === unit.id || p.unit_number === unit.unit_number);
        return {
          id: unit.id,
          number: unit.unit_number || unit.number || "?",
          months: MONTHS.map((_, mi) => {
            if (unit.status === "vacant") return "vacant";
            const p = unitPayments[mi];
            if (!p) return "pending";
            if (p.status === "Paid" && !p.was_late) return "paid";
            if (p.status === "Paid" && p.was_late) return "late";
            if (p.status === "Pending Approval") return "pending";
            if (p.status === "Late" || p.status === "Collections") return "missed";
            return "paid";
          }),
        };
      }),
    }));
  }

  useEffect(() => { fetchDashboard(); }, [fetchDashboard]);

  const today = new Date().toLocaleDateString("en-ZA", { weekday: "long", day: "numeric", month: "long", year: "numeric" });
  const r     = data?.raw || {};

  return (
    <div style={{ background: C.black, margin: "-1rem -1.8rem", minHeight: "100vh" }}>
      <style>{`
        @keyframes spin    { to { transform: rotate(360deg); } }
        @keyframes fadeup  { from { opacity:0; transform:translateY(10px); } to { opacity:1; transform:translateY(0); } }
        .dash-body { display: grid; grid-template-columns: 1fr 260px 280px; min-height: calc(100vh - 160px); }
        .dash-col  { border-right: 1px solid #2a2a2a; }
        .dash-col:last-child { border-right: none; }
        @media (max-width: 1100px) { .dash-body { grid-template-columns: 1fr 260px !important; } .dash-col:last-child { display: none !important; } }
        @media (max-width: 700px)  { .dash-body { grid-template-columns: 1fr !important; } .dash-col { border-right: none !important; border-bottom: 1px solid #2a2a2a; } }
        ::-webkit-scrollbar { display: none; }
      `}</style>

      {/* HERO */}
      <HeroBanner name={data?.landlordName ?? "—"} date={today} onRefresh={fetchDashboard} loading={loading} />

      {/* NAV */}
      <NavStrip navigate={navigate} />

      {/* LOADER */}
      {loading && (
        <div style={{ display: "flex", alignItems: "center", justifyContent: "center", padding: "8rem 0", gap: ".8rem" }}>
          <span style={{ width: 24, height: 24, border: "2px solid rgba(245,240,232,.07)", borderTopColor: C.gold, borderRadius: "50%", animation: "spin .7s linear infinite" }} />
          <span style={{ fontSize: ".75rem", fontFamily: F.mono, color: "rgba(245,240,232,.2)", letterSpacing: ".1em" }}>LOADING PORTFOLIO</span>
        </div>
      )}

      {!loading && data && (
        <div className="dash-body" style={{ animation: "fadeup .4s ease" }}>

          {/* ══ COL 1 — HEAT MATRIX ═══════════════════ */}
          <Panel
            title="Payment history matrix — last 6 months"
            action="Payments"
            onAction={() => navigate("/landlord/payments")}
            style={{ borderRight: `1px solid ${C.border}` }}
          >
            <HeatMatrix properties={data.heatMatrix} />
          </Panel>

          {/* ══ COL 2 — TIMELINE ══════════════════════ */}
          <div className="dash-col" style={{ display: "flex", flexDirection: "column" }}>
            <Panel title="Event timeline" action="All" onAction={() => navigate("/landlord/payments")} style={{ flex: 1 }}>
              {data.events.length === 0 ? (
                <p style={{ fontSize: ".68rem", fontFamily: F.mono, color: "rgba(245,240,232,.2)", padding: "2rem 0", textAlign: "center" }}>No recent events</p>
              ) : (
                <div>
                  {data.events.map((evt, i) => (
                    <TimelineEvent key={i} event={evt} last={i === data.events.length - 1} />
                  ))}
                </div>
              )}
            </Panel>
          </div>

          {/* ══ COL 3 — RINGS + ALERTS ════════════════ */}
          <div className="dash-col" style={{ display: "flex", flexDirection: "column" }}>

            {/* Ring meters */}
            <Panel title="Portfolio health">
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: ".5rem", marginBottom: "1.2rem" }}>
                <RingMeter value={data.rings.occupancy}   color={data.rings.occupancy  >= 80 ? C.greenLight : C.gold} label="Occupancy"   sublabel={`${r.occUnits}/${r.totUnits} units`} size={80} />
                <RingMeter value={data.rings.collection}  color={data.rings.collection >= 80 ? C.greenLight : C.gold} label="Collection"  sublabel={fmtK(r.collected)} size={80} />
                <RingMeter value={data.rings.onTime}      color={data.rings.onTime     >= 70 ? C.greenLight : C.redLight} label="On time"  sublabel="paid tenants"  size={80} />
              </div>

              {/* Summary figures */}
              <div style={{ borderTop: `1px solid ${C.border}`, paddingTop: ".9rem" }}>
                {[
                  { label: "Total tenants",   value: r.tenants,    color: C.white },
                  { label: "Collected",       value: fmtK(r.collected || 0),  color: C.greenLight },
                  { label: "Outstanding",     value: fmtK((r.expected || 0) - (r.collected || 0)), color: C.redLight },
                ].map((row, i, arr) => (
                  <div key={row.label} style={{
                    display: "flex", justifyContent: "space-between", alignItems: "center",
                    padding: ".35rem 0",
                    borderBottom: i < arr.length - 1 ? `1px solid rgba(42,42,42,.5)` : "none",
                  }}>
                    <span style={{ fontSize: ".65rem", color: "rgba(245,240,232,.35)", fontFamily: F.dm }}>{row.label}</span>
                    <span style={{ fontFamily: F.bebas, fontSize: ".85rem", color: row.color, letterSpacing: ".04em" }}>{row.value}</span>
                  </div>
                ))}
              </div>
            </Panel>

            {/* Alerts */}
            <Panel title="Alerts" style={{ borderTop: `1px solid ${C.border}` }}>
              <AlertBadge count={r.pending}     color={C.redLight}   label="Payments awaiting approval"    icon="credit-card"    onClick={() => navigate("/landlord/payments")} />
              <AlertBadge count={r.overdue}     color={C.redLight}   label="Overdue payments"              icon="alert-circle"   onClick={() => navigate("/landlord/payments")} />
              <AlertBadge count={r.expiring}    color={C.gold}       label="Leases expiring in 30 days"    icon="clock"          onClick={() => navigate("/landlord/leases")} />
              <AlertBadge count={r.expired}     color={C.redLight}   label="Expired leases need action"    icon="file-text"      onClick={() => navigate("/landlord/leases")} />
              <AlertBadge count={r.maintenance} color={C.gold}       label="Open maintenance requests"     icon="tool"           onClick={() => navigate("/landlord/maintenance")} />
              <AlertBadge count={r.complaints}  color={C.purple}     label="Active complaints"             icon="message-square" onClick={() => navigate("/landlord/complaints")} />
              {!r.pending && !r.overdue && !r.expiring && !r.expired && !r.maintenance && !r.complaints && (
                <div style={{ display: "flex", alignItems: "center", gap: ".4rem", padding: ".6rem 0" }}>
                  <div style={{ width: 6, height: 6, borderRadius: "50%", background: C.greenLight }} />
                  <span style={{ fontFamily: F.mono, fontSize: ".6rem", letterSpacing: ".08em", color: C.greenLight, textTransform: "uppercase" }}>All clear</span>
                </div>
              )}
            </Panel>
          </div>

        </div>
      )}
    </div>
  );
}